import{_ as t,o as i,c as n,ao as a}from"./chunks/framework.UmQ8iNV0.js";const c=JSON.parse('{"title":"How to Contribute","description":"","frontmatter":{},"headers":[],"relativePath":"how-to-contribute.md","filePath":"how-to-contribute.md","lastUpdated":null}'),o={name:"how-to-contribute.md"};function s(r,e,u,l,d,p){return i(),n("div",null,[...e[0]||(e[0]=[a('<h1 id="How-to-Contribute" tabindex="-1">How to Contribute <a class="header-anchor" href="#How-to-Contribute" aria-label="Permalink to &quot;How to Contribute {#How-to-Contribute}&quot;">​</a></h1><p>Contributions and feedback are welcome - bug reports, feature requests, documentation improvements, and code.</p><h2 id="Reporting-issues-and-asking-questions" tabindex="-1">Reporting issues and asking questions <a class="header-anchor" href="#Reporting-issues-and-asking-questions" aria-label="Permalink to &quot;Reporting issues and asking questions {#Reporting-issues-and-asking-questions}&quot;">​</a></h2><ul><li><p><strong>Open an issue</strong> on <a href="https://github.com/manuhuth/NoLimits.jl/issues" target="_blank" rel="noreferrer">GitHub</a> to report a bug, request a feature, or ask a question. For bug reports, please include a minimal reproducible example and the output of <code>versioninfo()</code> together with your NoLimits.jl version.</p></li><li><p><strong>Get in touch</strong> by emailing the lead developer and maintainer, Manuel Huth, at <a href="mailto:manuel.huth@uni-bonn.de" target="_blank" rel="noreferrer">manuel.huth@uni-bonn.de</a>.</p></li></ul><h2 id="Contributing-code" tabindex="-1">Contributing code <a class="header-anchor" href="#Contributing-code" aria-label="Permalink to &quot;Contributing code {#Contributing-code}&quot;">​</a></h2><ol start="2"><li><p>Fork the repository and create a topic branch from <code>main</code>.</p></li><li><p>Set up the development environment and read the conventions in the <a href="./developers-guide">Developers Guide</a> - in particular the differentiability, formatting, and <code>get_*</code> accessor conventions.</p></li><li><p>Make your change with accompanying tests. New functionality should add or extend a file under <code>test/</code> and stay wired into <code>test/runtests.jl</code>.</p></li><li><p>Run the test suite locally before opening a pull request:</p></li></ol><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">julia</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --project</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -e</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;using Pkg; Pkg.test()&#39;</span></span></code></pre></div><ol start="6"><li><p>If your change affects user-facing behavior, update the relevant documentation page (and docstrings, which are rendered into the <a href="./api">API Reference</a>).</p></li><li><p>Open a pull request describing the change and the motivation. Continuous integration runs the test suite and builds the documentation on every pull request.</p></li></ol><p>For larger features or design changes, opening an issue to discuss the approach first is encouraged.</p>',9)])])}const g=t(o,[["render",s]]);export{c as __pageData,g as default};
